    /**
     * Entra em um no da arvore: imprime o nome do no e incrementa o nivel.
     * No-op quando verbose=false.
     */
    private void enter(String name) {
        if (!verbose) return;
        printIndent();
        System.out.println("[" + name + "]");
        indent += 2;
    }

    /**
     * Sai de um no da arvore: decrementa o nivel.
     * No-op quando verbose=false.
     */
    private void leave() {
        if (!verbose) return;
        if (indent >= 2) indent -= 2;
    }

    /**
     * Exibe uma informacao dentro do no atual.
     * No-op quando verbose=false.
     */
    private void info(String msg) {
        if (!verbose) return;
        printIndent();
        System.out.println(msg);
    }

    /** Imprime espacos de acordo com o nivel de indentacao. */
    private void printIndent() {
        for (int i = 0; i < indent; i++) System.out.print(' ');
    }

